import React, { useState, useEffect } from 'react';
import axios from 'axios';
import ThemeToggle from './ThemeToggle';
import './App.css';
import Editor from "@monaco-editor/react";

function App() {
  const [files, setFiles] = useState(() => {
    const savedFiles = localStorage.getItem("files");
    return savedFiles
      ? JSON.parse(savedFiles)
      : [
          {
            id: 1,
            filename: "index.html",
            content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Saurabh IDE</title>
  <link rel="stylesheet" href="index.css" />
</head>
<body>
  <div class="container">
    <h1 id="title">Hello Coder</h1>
    <p class="subtitle">Welcome to your coding playground</p>
    <p class="author">by Saurabh Singh</p>
    <button id="btn">Start Coding</button>
  </div>
  <script src="index.js"></script>
</body>
</html>`
          },
          {
            id: 2,
            filename: "index.css",
            content: `* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  background: linear-gradient(135deg, #0f172a, #1e293b);
  color: white;
  font-family: Inter, Arial, sans-serif;
}

.container {
  text-align: center;
  padding: 40px;
}

h1 {
  font-size: 3rem;
  margin-bottom: 15px;
  background: linear-gradient(90deg, #38bdf8, #818cf8);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.subtitle {
  font-size: 1.2rem;
  color: #cbd5e1;
}

.author {
  margin-top: 10px;
  color: #94a3b8;
}

button {
  margin-top: 30px;
  padding: 14px 28px;
  border: none;
  border-radius: 10px;
  background: #3b82f6;
  color: white;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

button:hover {
  transform: translateY(-3px);
  background: #2563eb;
  box-shadow: 0 10px 25px rgba(59, 130, 246, 0.35);
}`
          },
          {
            id: 3,
            filename: "index.js",
            content: `const btn = document.getElementById("btn");
const title = document.getElementById("title");

btn.addEventListener("click", () => {
  title.textContent = "Happy Coding";
  btn.textContent = "Let's Build";
});`
          }
        ];
  });

  const [activeFileId, setActiveFileId] = useState(() => {
    const saved = localStorage.getItem("activeFileID");
    return saved ? Number(saved) : null;
  });
  
  const [showCreateInput, setShowCreateInput] = useState(false);
  const [newFileName, setNewFileName] = useState("");
  const [code, setCode] = useState("");
  const [showFiles, setShowFiles] = useState(true);
  const [showAI, setShowAI] = useState(true);
  const [prompt, setPrompt] = useState('');
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [theme, setTheme] = useState(localStorage.getItem("theme") || "dark");

  const activeFile = files.find(file => file.id === activeFileId);

  // Set active file ID when files load
  useEffect(() => {
    if (files.length > 0 && activeFileId === null) {
      setActiveFileId(files[0].id);
    }
  }, [files, activeFileId]);

  // Save active file ID to localStorage
  useEffect(() => {
    if (activeFileId !== null) {
      localStorage.setItem("activeFileID", activeFileId);
    }
  }, [activeFileId]);

  // Update code when active file changes
  useEffect(() => {
    const activeFile = files.find(file => file.id === activeFileId);
    if (activeFile) {
      setCode(activeFile.content);
    } else if (files.length > 0) {
      setCode(files[0].content);
    } else {
      setCode("// Write your code here");
    }
  }, [files, activeFileId]);

  // Save files to localStorage
  useEffect(() => {
    localStorage.setItem("files", JSON.stringify(files));
  }, [files]);

  const handleSubmit = async () => {
    if (!prompt.trim()) {
      setMessages((prev) => [
        ...prev,
        {
          type: 'error',
          text: 'Please enter a prompt!'
        }
      ]);
      return;
    }

    const userMessage = {
      type: 'user',
      text: prompt
    };

    setMessages((prev) => [...prev, userMessage]);
    const currentPrompt = prompt;
    setPrompt('');
    setLoading(true);

    const requestPayload = {
      code,
      prompt: currentPrompt
    };

    console.log('📤 Sending to Backend:', JSON.stringify(requestPayload, null, 2));

    try {
      const response = await axios.post(
        'http://localhost:5000/api/improve-code',
        requestPayload
      );

      console.log('✅ Response Received');
      console.log('📥 Response Data:', response.data);

      const improvedCode = response.data.improvedCode;
      setCode(improvedCode);

      // Save the improved code to the current file
      setFiles(prev =>
        prev.map(file =>
          file.id === activeFileId
            ? { ...file, content: improvedCode }
            : file
        )
      );

      const aiMessage = {
        type: 'ai',
        text: 'Code updated successfully!',
        code: improvedCode
      };

      setMessages((prev) => [...prev, aiMessage]);
      console.log('✅ UI Updated');
    } catch (err) {
      console.error('❌ ERROR:', err);
      const errorMessage = {
        type: 'error',
        text: `Error: ${err.response?.data?.error || err.message}`
      };
      setMessages((prev) => [...prev, errorMessage]);
    } finally {
      setLoading(false);
      console.log('========== FRONTEND REQUEST COMPLETE ==========\n');
    }
  };

  const createFile = () => {
    if (!newFileName.trim()) return;

    const newFile = {
      id: Date.now(),
      filename: newFileName,
      content: ""
    };

    setFiles((prev) => [...prev, newFile]);
    setActiveFileId(newFile.id);
    setNewFileName("");
    setShowCreateInput(false);
  };

  const handleFileClick = (fileId) => {
    const file = files.find(f => f.id === fileId);
    if (file) {
      setActiveFileId(fileId);
      setCode(file.content);
    }
  };

  const saveCurrentFile = () => {
    setFiles(prev =>
      prev.map(file =>
        file.id === activeFileId
          ? { ...file, content: code }
          : file
      )
    );
  };

  const deleteFile = (fileId) => {
    if (files.length === 1) {
      alert("Cannot delete the last file");
      return;
    }
    
    setFiles(prev => prev.filter(file => file.id !== fileId));
    
    if (activeFileId === fileId) {
      const remainingFiles = files.filter(file => file.id !== fileId);
      if (remainingFiles.length > 0) {
        setActiveFileId(remainingFiles[0].id);
      }
    }
  };

  const runHtml = () => {
    if (!activeFile) return;

    let finalHtml = activeFile.content;

    // Replace CSS files
    const cssMatches = [
      ...finalHtml.matchAll(/<link[^>]*href=["']([^"']+)["'][^>]*>/gi)
    ];

    cssMatches.forEach((match) => {
      const filePath = match[1];
      const fileName = filePath.split("/").pop();
      const cssFile = files.find(
        (f) => f.filename.toLowerCase() === fileName.toLowerCase()
      );

      if (cssFile) {
        finalHtml = finalHtml.replace(
          match[0],
          `<style>\n${cssFile.content}\n</style>`
        );
      }
    });

    // Replace JS files
    const jsMatches = [
      ...finalHtml.matchAll(/<script[^>]*src=["']([^"']+)["'][^>]*><\/script>/gi)
    ];

    jsMatches.forEach((match) => {
      const filePath = match[1];
      const fileName = filePath.split("/").pop();
      const jsFile = files.find(
        (f) => f.filename.toLowerCase() === fileName.toLowerCase()
      );

      if (jsFile) {
        finalHtml = finalHtml.replace(
          match[0],
          `<script>\n${jsFile.content}\n<\/script>`
        );
      }
    });

    // Create preview
    const blob = new Blob([finalHtml], { type: "text/html" });
    const previewUrl = URL.createObjectURL(blob);
    const previewWindow = window.open(previewUrl, "_blank", "noopener,noreferrer");

    // Memory cleanup
    setTimeout(() => {
      URL.revokeObjectURL(previewUrl);
    }, 10000);
  };

  const getLanguage = (fileName) => {
    const ext = fileName?.split(".").pop()?.toLowerCase();

    switch (ext) {
      case "html":
        return "html";
      case "js":
        return "javascript";
      case "css":
        return "css";
      case "json":
        return "json";
      case "ts":
        return "typescript";
      default:
        return "plaintext";
    }
  };

  return (
    <div className="app-container">
      {/* FILE EXPLORER */}
      {showFiles && (
        <div className="file-sidebar">
          <div className="panel-header">
            <h3>📁 File Structure</h3>
          </div>

          <div className="file-tree">
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                marginBottom: '10px'
              }}
            >
              <div>📁 src</div>
              <button
                onClick={() => setShowCreateInput(true)}
                className="add-file-btn"
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  fontSize: '18px'
                }}
              >
                ➕
              </button>
            </div>

            {showCreateInput && (
              <input
                type="text"
                placeholder="File name..."
                value={newFileName}
                onChange={(e) => setNewFileName(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    createFile();
                  }
                }}
                onBlur={() => {
                  if (!newFileName.trim()) {
                    setShowCreateInput(false);
                  }
                }}
                autoFocus
                style={{
                  width: '100%',
                  padding: '5px',
                  marginBottom: '10px',
                  borderRadius: '4px',
                  border: '1px solid #ccc'
                }}
              />
            )}

            <div style={{ paddingLeft: '18px' }}>
              {files.map((file) => (
                <div
                  key={file.id}
                  className={`file-item ${activeFileId === file.id ? 'active' : ''}`}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    cursor: 'pointer',
                    padding: '8px 5px',
                    backgroundColor: activeFileId === file.id ? '#e0e0e0' : 'transparent',
                    borderRadius: '4px',
                    marginBottom: '2px'
                  }}
                >
                  <span 
                    onClick={() => handleFileClick(file.id)}
                    style={{ flex: 1 }}
                  >
                    📄 {file.filename}
                  </span>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      deleteFile(file.id);
                    }}
                    style={{
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      color: 'red',
                      fontSize: '14px',
                      padding: '0 5px'
                    }}
                  >
                    ✖
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* CODE EDITOR */}
      <div className="editor-panel">
        <div className="panel-header">
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '10px'
            }}
          >
            <button
              className="toggle-btn"
              onClick={() => setShowFiles(!showFiles)}
              style={{
                padding: '5px 10px',
                cursor: 'pointer',
                borderRadius: '4px',
                border: 'none'
              }}
            >
              ☰
            </button>

            <button
              className="toggle-btn"
              onClick={() => setShowAI(!showAI)}
              style={{
                padding: '5px 10px',
                cursor: 'pointer',
                borderRadius: '4px',
                border: 'none'
              }}
            >
              🤖
            </button>

            <h3>Code Editor</h3>
          </div>

          <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
            <button
              onClick={saveCurrentFile}
              style={{
                padding: '5px 10px',
                backgroundColor: '#4CAF50',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              💾 Save
            </button>
            <button
              onClick={runHtml}
              style={{
                padding: '5px 10px',
                backgroundColor: activeFile?.filename?.toLowerCase().endsWith(".html") ? '#2196F3' : '#ccc',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: activeFile?.filename?.toLowerCase().endsWith(".html") ? 'pointer' : 'not-allowed'
              }}
              disabled={!activeFile?.filename?.toLowerCase().endsWith(".html")}
            >
              ▶ Run
            </button>
            <ThemeToggle onThemeChange={setTheme} />
          </div>
        </div>

        <Editor
          height="calc(100vh - 60px)"
          language={getLanguage(activeFile?.filename)}
          theme={theme === "light" ? "vs-light" : "vs-dark"}
          value={code}
          onChange={(value) => {
            setCode(value || "");
          }}
          options={{
            minimap: { enabled: false },
            fontSize: 14,
            wordWrap: 'on'
          }}
        />
      </div>

      {/* AI PANEL */}
      {showAI && (
        <div className="chat-panel">
          <div className="panel-header">
            <h3>🤖 AI Assistant</h3>
            <button
              className="toggle-btn"
              onClick={() => setShowAI(false)}
              style={{
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                fontSize: '18px'
              }}
            >
              ✖
            </button>
          </div>

          <div className="chat-messages" style={{
            flex: 1,
            overflowY: 'auto',
            padding: '15px',
            display: 'flex',
            flexDirection: 'column',
            gap: '10px'
          }}>
            {messages.length === 0 ? (
              <div className="empty-chat" style={{
                textAlign: 'center',
                color: '#666',
                padding: '20px'
              }}>
                <p>👋 Hi! I'm your AI code assistant.</p>
                <p>Ask me to improve, fix, or explain your code!</p>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div 
                  key={idx} 
                  className={`message ${msg.type}`}
                  style={{
                    padding: '10px',
                    borderRadius: '8px',
                    backgroundColor: msg.type === 'user' ? '#e3f2fd' : msg.type === 'ai' ? '#f3e5f5' : '#ffebee',
                    alignSelf: msg.type === 'user' ? 'flex-end' : 'flex-start',
                    maxWidth: '80%'
                  }}
                >
                  <div className="message-label" style={{
                    fontWeight: 'bold',
                    fontSize: '12px',
                    marginBottom: '5px'
                  }}>
                    {msg.type === 'user' ? '👤 You' : msg.type === 'ai' ? '🤖 AI' : '⚠️ Error'}
                  </div>
                  <div className="message-text">{msg.text}</div>
                </div>
              ))
            )}

            {loading && (
              <div className="message ai" style={{
                padding: '10px',
                borderRadius: '8px',
                backgroundColor: '#f3e5f5',
                alignSelf: 'flex-start',
                maxWidth: '80%'
              }}>
                <div className="message-label" style={{
                  fontWeight: 'bold',
                  fontSize: '12px',
                  marginBottom: '5px'
                }}>🤖 AI</div>
                <div className="message-text loading">Thinking...</div>
              </div>
            )}
          </div>

          <div className="chat-input-section" style={{
            padding: '15px',
            borderTop: '1px solid #e0e0e0',
            display: 'flex',
            gap: '10px'
          }}>
            <input
              type="text"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Ask AI to improve your code..."
              disabled={loading}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !loading) {
                  handleSubmit();
                }
              }}
              style={{
                flex: 1,
                padding: '10px',
                borderRadius: '4px',
                border: '1px solid #ccc',
                fontSize: '14px'
              }}
            />
            <button 
              onClick={handleSubmit} 
              disabled={loading || !prompt.trim()}
              style={{
                padding: '10px 20px',
                backgroundColor: loading || !prompt.trim() ? '#ccc' : '#2196F3',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: loading || !prompt.trim() ? 'not-allowed' : 'pointer'
              }}
            >
              {loading ? '⏳' : '🚀'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
